define i32 @mul_by_150_sdiv_by_100(i32 %0) {
  %2 = mul nuw i32 %0, -150
  %3 = sdiv i32 %2, -100
  ret i32 %3
}

define i32 @mul_by_3_sdiv_by_2(i32 %0) {
  %2 = mul nuw i32 %0, -3
  %3 = sdiv i32 %2, -2
  ret i32 %3
}

define i32 @sdiv_mul_nsw_sub_nsw(i32 %x, i32 %y) {
  %m = mul nsw i32 %y, %x
  %n = sub nsw i32 0, %m
  %d = sdiv i32 %m, %n
  ret i32 %d
}

define i32 @sdiv_mul_sub_nsw(i32 %x, i32 %y) {
  %m = mul i32 %y, %x
  %n = sub nsw i32 0, %m
  %d = sdiv i32 %m, %n
  ret i32 %d
}
